import psycopg2
from sqlalchemy import create_engine, text

def connect_to_db(db_host, db_name):
    try:
        conn = psycopg2.connect(host=db_host, database=db_name)
        return conn.cursor()
    except (Exception, psycopg2.Error) as error:
        print("Failed to connect", error)

def search_users(username=None, email=None, role=None, status=None):
    cursor = connect_to_db('localhost', 'mydatabase')
    
    query = text("""
        SELECT *
        FROM users
        WHERE (
            username ILIKE :username
            OR email ILIKE :email
            OR role = :role
            OR status = :status
        )
    """)
    
    params = {
        'username': f'%{username}%' if username else None,
        'email': f'%{email}%' if email else None,
        'role': role,
        'status': status
    }
    
    results = cursor.execute(query, params).fetchall()
    return results

# Example usage:
print(search_users(username='john', role='admin', status='active'))